CREATE OR REPLACE VIEW vr_isu_loan_con (membership_no, loan_name, loan_type_description, loan_contract_no, loan_approve_amount, insurance_cost, total_share_value, insure_rate, insure_full, duty, tax, insurance_approve, company_desc, protec_begin) AS SELECT sc_lon_m_contract.membership_no,
         sc_lon_m_contract.loan_name,   
         sc_lon_m_rule.loan_type_description,  
         sc_lon_m_contract.loan_contract_no ,
         sc_lon_m_contract.loan_approve_amount, 
