         sc_mem_m_share_mem.share_stock as total_share_value,   
         0.34 AS INSURE_RATE ,
         PKA_LON_REQFEE.fp_port_calc_insure_full(  sc_mem_m_insure.latest_insurance_cost ) as INSURE_FULL ,
         PKA_LON_REQFEE.fp_port_calc_insure_duty(  PKA_LON_REQFEE.fp_port_calc_insure_full(  sc_mem_m_insure.latest_insurance_cost ) ) as DUTY ,
         PKA_LON_REQFEE.fp_port_calc_insure_tax( PKA_LON_REQFEE.fp_port_calc_insure_full(  sc_mem_m_insure.latest_insurance_cost )   , PKA_LON_REQFEE.fp_port_calc_insure_duty(  PKA_LON_REQFEE.fp_port_calc_insure_full(  sc_mem_m_insure.latest_insurance_cost )    )   ) as TAX ,
         sc_mem_m_insure.insurance_approve ,   
         sc_mem_m_ucf_insure_status.company_desc AS COMPANY_DESC,
         sc_mem_m_insure.protec_begin 
         FROM sc_lon_m_contract,   
         sc_mem_m_share_mem,   
