         sc_mem_m_ucf_insure_status
   WHERE ( sc_lon_m_contract.membership_no = sc_mem_m_share_mem.membership_no ) and ( sc_lon_m_contract.loan_contract_no = sc_mem_m_insure.insurance_no ) and ( sc_lon_m_contract.loan_type = sc_lon_m_rule.loan_type ) and ( sc_mem_m_ucf_insure_status.company_status =  sc_mem_m_insure.company_status )
and sc_mem_m_ucf_insure_status.company_status != 'NEW' 

/*WHERE*/

